all_bars = []
for batch in [okx_chunk1, okx_chunk2, okx_chunk3]:
    for item in batch:
        ts_ms = int(item[0])
        all_bars.append({
            "timestamp_ms": ts_ms,
            "timestamp": datetime.fromtimestamp(ts_ms/1000.0, tz=timezone.utc).isoformat(),
            "open": float(item[1]),
            "high": float(item[2]),
            "low": float(item[3]),
            "close": float(item[4]),
            "volume": float(item[5]) if float(item[5]) > 0 else 1.0,
            "symbol": "REAL_OKX_XAU-USDT-SWAP"
        })

unique_bars = {b["timestamp_ms"]: b for b in all_bars}
sorted_bars = sorted(unique_bars.values(), key=lambda x: x["timestamp_ms"])

with sqlite3.connect("History.db") as conn:
    cursor = conn.cursor()
    cursor.execute("""
    CREATE TABLE IF NOT EXISTS real_historical_klines (
        timestamp_ms INTEGER PRIMARY KEY,
        datetime_utc TEXT NOT NULL,
        symbol TEXT NOT NULL,
        open REAL NOT NULL,
        high REAL NOT NULL,
        low REAL NOT NULL,
        close REAL NOT NULL,
        volume REAL NOT NULL
    )
    """)
    cursor.executemany("""
    INSERT OR REPLACE INTO real_historical_klines (timestamp_ms, datetime_utc, symbol, open, high, low, close, volume)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    """, [(b["timestamp_ms"], b["timestamp"], b["symbol"], b["open"], b["high"], b["low"], b["close"], b["volume"]) for b in sorted_bars])
    conn.commit()

print(f"✅ Ingested {len(sorted_bars)} REAL historical OKX 5-minute candles into History.db cache.")
